async function enviarDatos(evento){const formData=new FormData();const region=document.getElementById('region')?.value||'';const ciudad=document.getElementById('ciudades')?.value||'';const activeTags=document.querySelectorAll('.btn.active.tag');const tags=Array.from(activeTags).map(btn=>btn.id);formData.append('region',region);formData.append('ciudad',ciudad);formData.append('tag',tags);formData.append('cuantos',tags.length);try{if(evento?.target?.id==='region'){const responseCiudades=await axios.post('regiones',formData);document.getElementById('ciudades').innerHTML=responseCiudades.data;}const responseTarjetas=await axios.post('filtrar',formData);document.getElementById('tarjetas').innerHTML=responseTarjetas.data;}catch(error){console.error('Error al filtrar:',error);alert('Hubo un problema al actualizar los resultados.');}}function inicializarFiltros(){document.getElementById('region')?.addEventListener('change',enviarDatos);document.getElementById('ciudades')?.addEventListener('change',enviarDatos);document.querySelectorAll('.btn.tag').forEach(btn=>{btn.addEventListener('click',enviarDatos);});}async function cargarContenido(url,push=true){try{const response=await axios.get(url);document.getElementById('contenido').innerHTML=response.data;if(push)history.pushState({url},'',url);inicializarFiltros();}catch(error){console.error('Error al cargar contenido:',error);document.getElementById('contenido').innerHTML='<p>Error al cargar el contenido.</p>';}}document.addEventListener('DOMContentLoaded',()=>{inicializarFiltros();});